hooks.command:
cat "$CLAUDE_TOOL_INPUT" | python3 -c "
import sys, json, re
data = json.load(sys.stdin)
path = data.get('file_path', data.get('path', ''))
if not any(path.endswith(ext) for ext in ('.js', '.ts', '.jsx', '.tsx')):
    sys.exit(0)
content = data.get('content', '') + data.get('new_string', '')
warnings = []
for i, line in enumerate(content.splitlines(), 1):
    if re.search(r'[^=!<>]==[^=]', line) or re.search(r'!=[^=]', line):
        if '===' not in line and '!==' not in line:
            warnings.append(f'  Line {i}: non-strict equality — use === or !==')
if warnings:
    print('WARN: non-strict equality detected:', file=sys.stderr)
    print('\n'.join(warnings), file=sys.stderr)
"
